SELECT APPROVAL_YN
FROM mhdb.TB_APPROVAL_LINE
WHERE approval_req_id = #{approvalReqId}
  AND USER_CD = #{userCd}

SELECT COUNT(*) AS cnt
FROM mhdb.TB_APPROVAL_REQ
WHERE REQ_DATE = #{reqDate}

SELECT LPAD((COUNT(1)+1)::TEXT,3,'0') AS seq
FROM mhdb.TB_APPROVAL_REQ
WHERE REQ_DATE = #{reqDate}

SELECT SUBSTRING(MAX(APPROVAL_REQ_ID), 9, 11) AS seq
FROM mhdb.TB_APPROVAL_REQ
WHERE REQ_DATE = #{reqDate}
